// Normalize callback payload
const body = $json.body || $json;
const result = body.parsedOutput?.result || "";

// Agent label mapping for subtasks
const agentLabelMap = {
  'planner': 'engineer-planner',
  'implementer': 'engineer-implementer',
  'reviewer': 'engineer-reviewer',
  'pm': 'product-manager',
  'ui': 'ui-engineer',
  'marketing': 'marketing',
  'creative-assets': 'creative-assets',
  'bug-triage': 'bug-triage',
  'security': 'security-agent',
  'sprint-report': 'sprint-reporter',
  'standup': 'sprint-reporter'
};

let subtasks = [];
let legacyActions = [];

// Parse [CREATE-SUBTASKS parent=XXX] blocks (NEW format)
const subtaskMatches = result.matchAll(/\[CREATE-SUBTASKS\s+parent=([^\]]+)\]([\s\S]*?)\[\/CREATE-SUBTASKS\]/g);
for (const match of subtaskMatches) {
  const parentKey = match[1].trim();
  const subtasksBlock = match[2];

  // Parse YAML-like subtask list
  const itemMatches = subtasksBlock.matchAll(/- summary:\s*(.+?)(?:\n|$)([\s\S]*?)(?=\n- summary:|$)/g);
  let index = 1;
  for (const item of itemMatches) {
    const summary = item[1].trim();
    const details = item[2] || '';

    // Extract fields
    const agentMatch = details.match(/agent:\s*(\S+)/);
    const blockedByMatch = details.match(/blockedBy:\s*\[([^\]]+)\]/);
    const descMatch = details.match(/description:\s*\|?\s*\n([\s\S]*?)(?=\n\s*\w+:|$)/) || details.match(/description:\s*([^\n]+)/);
    const filesMatch = details.match(/files:\s*\[([^\]]+)\]/);
    const priorityMatch = details.match(/priority:\s*(\S+)/);
    const labelsMatch = details.match(/labels:\s*\[([^\]]+)\]/);

    const agent = agentMatch ? agentMatch[1] : 'implementer';
    const blockedBy = blockedByMatch ? blockedByMatch[1].split(',').map(s => s.trim()) : [];
    const description = descMatch ? descMatch[1].trim() : '';
    const files = filesMatch ? filesMatch[1].split(',').map(s => s.trim().replace(/["']/g, '')) : [];
    const priority = priorityMatch ? priorityMatch[1] : 'medium';
    const extraLabels = labelsMatch ? labelsMatch[1].split(',').map(s => s.trim().replace(/["']/g, '')) : [];

    subtasks.push({
      localIndex: index,
      parentKey,
      summary,
      agent: agentLabelMap[agent] || agent,
      agentLabel: `agent:${agent}`,
      blockedBy,
      description,
      files,
      priority,
      extraLabels
    });
    index++;
  }
}

// Parse legacy [DISPATCH-ACTIONS] block (for backwards compatibility)
const dispatchMatch = result.match(/\[DISPATCH-ACTIONS\]([\s\S]*?)\[\/DISPATCH-ACTIONS\]/);
if (dispatchMatch) {
  const actionsBlock = dispatchMatch[1];
  const actionMatches = actionsBlock.matchAll(/- action:\s*(\S+)\s+issueKey:\s*(\S+)/g);
  for (const m of actionMatches) {
    legacyActions.push({ action: m[1], issueKey: m[2] });
  }
}

// Phase 3.4: Post-acceptance automation
const hasAutoAccept = result.includes('[AUTO-ACCEPT]') && !result.includes('[AUTO-ACCEPT-REJECTED]') && !result.includes('[AUTO-ACCEPT-FAILED]');
const issueKey = body.issueKey;

// For accepted issues, auto-add follow-up subtasks
if (hasAutoAccept && issueKey && subtasks.length === 0) {
  // Convert label-based triggers to subtasks
  if (result.includes('needs-marketing') || result.includes('label: needs-marketing')) {
    subtasks.push({
      localIndex: subtasks.length + 1,
      parentKey: issueKey,
      summary: 'Create marketing content',
      agent: 'marketing',
      agentLabel: 'agent:marketing',
      blockedBy: [],
      description: 'Create marketing content for new feature',
      files: [],
      priority: 'medium'
    });
  }
  // Create PR after acceptance (implementer now handles PR creation)
  subtasks.push({
    localIndex: subtasks.length + 1,
    parentKey: issueKey,
    summary: 'Create pull request',
    agent: 'engineer-implementer',
    agentLabel: 'agent:implementer',
    blockedBy: [],
    description: 'Create pull request for accepted implementation',
    files: [],
    priority: 'high'
  });
  // Release notes handled directly by PM (no separate agent needed)
}

// Combine: subtasks take priority, fall back to legacy actions
const hasSubtasks = subtasks.length > 0;
const hasLegacyActions = legacyActions.length > 0;

return [{
  json: {
    ok: true,
    jobId: body.jobId,
    status: body.status,
    agent: body.agent,
    issueKey: body.issueKey,
    error: body.error,
    parsedOutput: body.parsedOutput,
    logUrl: body.logUrl,
    telegram: body.telegram || body.gchat || body.slack || null,
    finishedAt: body.finishedAt,
    batchId: body.batchId || null,
    workingDir: body.workingDir || (() => { const PD = { CER: '{{DEFAULT_WORKING_DIR}}', EOS: '{{DEFAULT_WORKING_DIR}}', WMS: '{{DEFAULT_WORKING_DIR}}' }; return PD[(body.issueKey || '').split('-')[0]] || null; })(),
    // New subtask-based dispatch
    subtasks: subtasks,
    hasSubtasks: hasSubtasks,
    // Legacy action-based dispatch (for backwards compatibility)
    dispatchActions: legacyActions,
    hasDispatchActions: hasLegacyActions && !hasSubtasks,
    hasAutoAccept: hasAutoAccept,
    event: body.event || 'completed',
    meetingAction: body.meetingAction || null,
    source: body.source || null
  }
}];

const batch = $json.batch;
const results = batch.results || [];

// Build summary lines
const lines = results.map(r => {
  const icon = (r.status === 'succeeded' || r.status === 'completed') ? '\u2705' : '\u274C';
  const key = r.issueKey || 'unknown';
  let text = r.result ? String(r.result).slice(0, 150) : (r.error || 'No result');
  // Clean up text
  text = text.replace(/\n/g, ' ').trim();
  if (text.length > 150) text = text.slice(0, 147) + '...';
  return `${icon} *${key}*: ${text}`;
});

const successCount = batch.completed || 0;
const failCount = batch.failed || 0;
const total = batch.total || 0;

const header = `*Batch Complete* (${successCount}/${total} succeeded${failCount > 0 ? `, ${failCount} failed` : ''})`;
const summary = header + '\n\n' + lines.join('\n');

return [{
  json: {
    batchId: batch.batchId,
    telegram: batch.gchat || batch.slack,
    summary,
    successCount,
    failCount,
    total
  }
}];

// Process subtasks: create in Jira with proper links
// This iterates through subtasks and prepares Jira API calls
const subtasks = $json.subtasks || [];
const issueKey = $json.issueKey;

if (subtasks.length === 0) {
  return [{ json: { skip: true, subtasks: [] } }];
}

// Group subtasks by parent for batch processing
const byParent = {};
for (const st of subtasks) {
  const parent = st.parentKey || issueKey;
  if (!byParent[parent]) byParent[parent] = [];
  byParent[parent].push(st);
}

// Output each subtask for individual creation
return subtasks.map(st => ({
  json: {
    subtask: st,
    parentKey: st.parentKey || issueKey,
    allSubtasks: subtasks,
    originalIssueKey: issueKey
  }
}));

// After subtask created, create blocking links if needed
const subtask = $json.subtask;
const createdKey = $('Create subtask in Jira').first().json.key;
const allSubtasks = $json.allSubtasks || [];
const blockedBy = subtask.blockedBy || [];

if (!createdKey) {
  return [{ json: { skip: true, error: 'No subtask key returned' } }];
}

// If this subtask has blockedBy references, we need to create links
// blockedBy contains local indices like [1, 2] or issue keys like ['CER-150']
const linksToCreate = [];
for (const ref of blockedBy) {
  // Check if it's a numeric local index or an issue key
  const refNum = parseInt(ref, 10);
  if (!isNaN(refNum)) {
    // Local index - find the subtask that was created with that index
    // Note: We'd need to track created subtasks' keys
    // For now, we'll need to handle this in a second pass
    linksToCreate.push({
      type: 'local',
      localIndex: refNum,
      createdKey: createdKey
    });
  } else {
    // Direct issue key reference
    linksToCreate.push({
      type: 'issueKey',
      blockerKey: ref,
      blockedKey: createdKey
    });
  }
}

return [{
  json: {
    createdKey,
    subtask,
    localIndex: subtask.localIndex,
    linksToCreate,
    allSubtasks
  }
}];

// After all subtasks created, trigger unblocked ones
// A subtask is unblocked if it has no blockedBy or all blockers have been resolved
const allItems = $input.all();
const createdSubtasks = [];

// Build mapping of localIndex -> createdKey
const indexToKey = {};
for (const item of allItems) {
  const data = item.json;
  if (data.createdKey && data.localIndex) {
    indexToKey[data.localIndex] = data.createdKey;
    createdSubtasks.push({
      key: data.createdKey,
      subtask: data.subtask,
      localIndex: data.localIndex
    });
  }
}

// Find subtasks that are unblocked (no blockers or all blockers are newly created)
const unblockedSubtasks = [];
for (const st of createdSubtasks) {
  const blockedBy = st.subtask.blockedBy || [];
  if (blockedBy.length === 0) {
    // No blockers - immediately trigger
    unblockedSubtasks.push(st);
  }
  // Subtasks with blockers will wait for those blockers to complete
  // The Subtask_Webhook_Listener will handle triggering them
}

// Return unblocked subtasks for immediate dispatch
if (unblockedSubtasks.length === 0) {
  return [{ json: { noUnblockedSubtasks: true, total: createdSubtasks.length } }];
}

return unblockedSubtasks.map(st => ({
  json: {
    issueKey: st.key,
    agent: st.subtask.agent,
    summary: st.subtask.summary,
    description: st.subtask.description,
    files: st.subtask.files || [],
    parentKey: st.subtask.parentKey
  }
}));

