// Generate batch ID for tracking dispatched jobs
const actions = $json.dispatchActions || [];
const gchat = $json.telegram;

if (actions.length === 0) {
  return [{ json: { skip: true } }];
}

// Generate a unique batch ID
const batchId = `batch_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;

return [{
  json: {
    batchId,
    total: actions.length,
    gchat,
    actions
  }
}];

// Map actions to runner jobs with batch ID
const actionMap = {
  'acceptance-review': 'product-manager',
  'code-review': 'engineer-reviewer',
  'implement': 'engineer-implementer',
  'plan': 'engineer-planner',
  'marketing': 'marketing',
  'create-pr': 'engineer-implementer',
  'bug-triage': 'bug-triage',
  'security-scan': 'security-agent',
  'release-notes': 'product-manager',
  'sprint-report': 'sprint-reporter',
  'standup': 'sprint-reporter'
};

const batchId = $json.batchId;
const actions = $('Prepare batch creation').first().json.actions || [];
const gchat = $('Prepare batch creation').first().json.gchat;

return actions.map(a => ({
  json: {
    job: {
      agent: actionMap[a.action] || a.action,
      issueKey: a.issueKey,
      workingDir: $('Normalize callback').first().json.workingDir,
      callbackUrl: "{{N8N_PUBLIC_URL}}/webhook/runner/callback",
      batchId: batchId,
      telegram: null // Don't post individual results, wait for batch summary
    },
    originalAction: a
  }
}));

// Post agent result as Jira comment for one-shot jobs
const event = $json.event || 'completed';
const issueKey = $json.issueKey;
const result = $json.parsedOutput?.result || '';
const agent = $json.agent || 'unknown';
const status = $json.status || 'unknown';

// Skip pipeline events and jobs without issueKey
if (!issueKey || event.startsWith('pipeline:')) {
  return [];
}

// Truncate for Jira (max ~30k chars)
const maxLen = 30000;
const truncResult = result.length > maxLen
  ? result.substring(0, maxLen) + '\n\n... (truncated)'
  : result;

// Build ADF comment body
const content = [
  {
    type: 'paragraph',
    content: [
      { type: 'text', text: `Agent: ${agent} | Status: ${status}`, marks: [{ type: 'strong' }] }
    ]
  }
];

if (truncResult) {
  content.push({
    type: 'codeBlock',
    attrs: { language: 'markdown' },
    content: [{ type: 'text', text: truncResult.substring(0, 28000) }]
  });
}

return [{
  json: {
    issueKey,
    commentBody: JSON.stringify({
      body: { type: 'doc', version: 1, content }
    })
  }
}];

// Find the Done transition
const transitions = $json.transitions || [];
const done = transitions.find(t => t.name?.toLowerCase() === 'done');

if (!done) {
  return [{ json: { skip: true, reason: 'No Done transition found' } }];
}

return [{
  json: {
    transitionId: done.id,
    issueKey: $('Normalize callback').first().json.issueKey
  }
}];

// Meshwork webhook caller verification.
// Accepts EITHER:
//   1) the runner's HMAC signature (x-meshwork-signature over `${ts}.${body}`)
//   2) a shared token in ?token= or the x-webhook-token header (for external
//      callers like Jira webhook URLs)
// Enforcement is off until WEBHOOK_VERIFICATION_ENFORCE=true in .env (values
// are substituted at import time by scripts/import-workflows.sh).
const crypto = require('crypto');

const ENFORCE = '{{WEBHOOK_VERIFICATION_ENFORCE}}'.toLowerCase() === 'true';
const RUNNER_SECRET = '{{RUNNER_SECRET}}';
const SHARED_TOKEN = '{{WEBHOOK_SHARED_TOKEN}}';

const item = $input.first().json;
const headers = item.headers || {};
const query = item.query || {};
const body = item.body ?? {};

const isPlaceholder = (v) => !v || v.indexOf('{{') === 0;
let ok = false;

// 1) Runner HMAC
const sig = headers['x-meshwork-signature'];
const ts = headers['x-meshwork-timestamp'];
if (sig && ts && !isPlaceholder(RUNNER_SECRET)) {
  const age = Math.abs(Date.now() - Number(ts));
  if (age < 5 * 60 * 1000) {
    const expected = 'sha256=' + crypto.createHmac('sha256', RUNNER_SECRET)
      .update(ts + '.' + JSON.stringify(body)).digest('hex');
    const a = crypto.createHash('sha256').update(expected).digest();
    const b = crypto.createHash('sha256').update(String(sig)).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

// 2) Shared token
if (!ok && !isPlaceholder(SHARED_TOKEN)) {
  const provided = String(query.token || headers['x-webhook-token'] || '');
  if (provided) {
    const a = crypto.createHash('sha256').update(provided).digest();
    const b = crypto.createHash('sha256').update(SHARED_TOKEN).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

if (!ok && ENFORCE) {
  throw new Error('Webhook verification failed: missing or invalid signature/token. See SECURITY.md (webhook verification).');
}

return $input.all();
